/**
 * Pure validation functions for order operations.
 *
 * No side effects, no database calls — these functions validate
 * inputs and business rules using only the data provided.
 */

import type { CreateOrderInput, OrderStatus } from '../models/order.js';

/**
 * Valid status transitions for orders.
 */
const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Validate that an order has at least one item.
 * Throws if the items array is empty.
 */
export function validateOrderItems(input: CreateOrderInput): void {
  if (input.items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Get the list of valid next statuses from a given status.
 */
export function getValidTransitions(from: OrderStatus): OrderStatus[] {
  return [...STATUS_TRANSITIONS[from]];
}

/**
 * Pure validation functions for user operations.
 *
 * No side effects, no database calls — these functions validate
 * input format and structure using only the data provided.
 */

import type { CreateUserInput, UpdateUserInput } from '../models/user.js';

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate that an email address has a valid format.
 */
export function validateEmail(email: string): boolean {
  return EMAIL_REGEX.test(email);
}

/**
 * Validate input for creating a new user.
 * Throws if any required field is missing or invalid.
 */
export function validateCreateUserInput(input: CreateUserInput): void {
  if (!input.name || input.name.trim().length === 0) {
    throw new Error('User name is required');
  }

  if (!input.email || input.email.trim().length === 0) {
    throw new Error('User email is required');
  }

  if (!validateEmail(input.email)) {
    throw new Error(`Invalid email format: ${input.email}`);
  }

  const validRoles = ['admin', 'member', 'viewer'];
  if (!validRoles.includes(input.role)) {
    throw new Error(`Invalid role: ${input.role}. Must be one of: ${validRoles.join(', ')}`);
  }
}

/**
 * Validate input for updating a user.
 * Only validates fields that are present in the input.
 */
export function validateUpdateUserInput(input: UpdateUserInput): void {
  if (input.name !== undefined && input.name.trim().length === 0) {
    throw new Error('User name cannot be empty');
  }

  if (input.email !== undefined) {
    if (input.email.trim().length === 0) {
      throw new Error('User email cannot be empty');
    }
    if (!validateEmail(input.email)) {
      throw new Error(`Invalid email format: ${input.email}`);
    }
  }

  if (input.role !== undefined) {
    const validRoles = ['admin', 'member', 'viewer'];
    if (!validRoles.includes(input.role)) {
      throw new Error(`Invalid role: ${input.role}. Must be one of: ${validRoles.join(', ')}`);
    }
  }
}

/**
 * Pure validation functions for notification operations.
 *
 * No side effects, no database calls — these functions evaluate
 * notification rules using only the data provided.
 */

import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationPayload } from '../models/notification.js';

/**
 * Determine whether a notification should be sent based on user preferences.
 *
 * Rules:
 * - Urgent priority notifications always go through.
 * - If no preferences exist, notifications are allowed (opt-out model).
 * - If email is disabled, email notifications are blocked.
 * - If the notification type is not in subscribedTypes, it is blocked.
 */
export function shouldSendNotification(
  prefs: UserPreferences | undefined,
  payload: NotificationPayload,
): boolean {
  // Urgent notifications always go through
  if (payload.priority === 'urgent') {
    return true;
  }

  // No preferences = default allow (opt-out model)
  if (!prefs) {
    return true;
  }

  // Check channel-specific preferences
  if (payload.channel === 'email') {
    if (!prefs.email.enabled) {
      return false;
    }

    if (!prefs.email.subscribedTypes.includes(payload.type)) {
      return false;
    }
  }

  return true;
