import { describe, it, expect } from 'vitest';
import {
  validateOrderItems,
  isValidStatusTransition,
  getValidTransitions,
} from '../../src/validators/order.validator.js';
import type { CreateOrderInput, OrderStatus } from '../../src/models/order.js';

describe('Order Validators', () => {
  describe('validateOrderItems', () => {
    it('should pass for input with items', () => {
      const input: CreateOrderInput = {
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      };
      expect(() => validateOrderItems(input)).not.toThrow();
    });

    it('should throw for empty items', () => {
      const input: CreateOrderInput = {
        userId: 'user-1',
        items: [],
      };
      expect(() => validateOrderItems(input)).toThrow('at least one item');
    });

    it('should pass for multiple items', () => {
      const input: CreateOrderInput = {
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
        ],
      };
      expect(() => validateOrderItems(input)).not.toThrow();
    });
  });

  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      expect(isValidStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidStatusTransition('delivered', 'cancelled')).toBe(false);
    });

    it('should reject cancelled -> any', () => {
      expect(isValidStatusTransition('cancelled', 'pending')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'confirmed')).toBe(false);
    });

    it('should reject shipped -> cancelled', () => {
      expect(isValidStatusTransition('shipped', 'cancelled')).toBe(false);
    });
  });

  describe('getValidTransitions', () => {
    it('should return valid transitions from pending', () => {
      expect(getValidTransitions('pending')).toEqual(['confirmed', 'cancelled']);
    });

    it('should return valid transitions from confirmed', () => {
      expect(getValidTransitions('confirmed')).toEqual(['shipped', 'cancelled']);
    });

    it('should return valid transitions from shipped', () => {
      expect(getValidTransitions('shipped')).toEqual(['delivered']);
    });

    it('should return empty array for terminal states', () => {
      expect(getValidTransitions('delivered')).toEqual([]);
      expect(getValidTransitions('cancelled')).toEqual([]);
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateEmail,
  validateCreateUserInput,
  validateUpdateUserInput,
} from '../../src/validators/user.validator.js';

describe('User Validators', () => {
  describe('validateEmail', () => {
    it('should accept valid emails', () => {
      expect(validateEmail('alice@example.com')).toBe(true);
      expect(validateEmail('user+tag@domain.co')).toBe(true);
      expect(validateEmail('a@b.c')).toBe(true);
    });

    it('should reject invalid emails', () => {
      expect(validateEmail('')).toBe(false);
      expect(validateEmail('notanemail')).toBe(false);
      expect(validateEmail('@domain.com')).toBe(false);
      expect(validateEmail('user@')).toBe(false);
      expect(validateEmail('user @domain.com')).toBe(false);
    });
  });

  describe('validateCreateUserInput', () => {
    it('should pass for valid input', () => {
      expect(() =>
        validateCreateUserInput({
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
        }),
      ).not.toThrow();
    });

    it('should throw for empty name', () => {
      expect(() =>
        validateCreateUserInput({
          name: '',
          email: 'alice@example.com',
          role: 'member',
        }),
      ).toThrow('User name is required');
    });

    it('should throw for whitespace-only name', () => {
      expect(() =>
        validateCreateUserInput({
          name: '   ',
          email: 'alice@example.com',
          role: 'member',
        }),
      ).toThrow('User name is required');
    });

    it('should throw for empty email', () => {
      expect(() =>
        validateCreateUserInput({
          name: 'Alice',
          email: '',
          role: 'member',
        }),
      ).toThrow('User email is required');
    });

    it('should throw for invalid email format', () => {
      expect(() =>
        validateCreateUserInput({
          name: 'Alice',
          email: 'notanemail',
          role: 'member',
        }),
      ).toThrow('Invalid email format');
    });

    it('should accept all valid roles', () => {
      for (const role of ['admin', 'member', 'viewer'] as const) {
        expect(() =>
          validateCreateUserInput({
            name: 'Alice',
            email: 'alice@example.com',
            role,
          }),
        ).not.toThrow();
      }
    });
  });

  describe('validateUpdateUserInput', () => {
    it('should pass for empty input (no changes)', () => {
      expect(() => validateUpdateUserInput({})).not.toThrow();
    });

    it('should pass for valid partial update', () => {
      expect(() =>
        validateUpdateUserInput({ name: 'Alice Smith' }),
      ).not.toThrow();
    });

    it('should throw for empty name', () => {
      expect(() => validateUpdateUserInput({ name: '' })).toThrow(
        'User name cannot be empty',
      );
    });

    it('should throw for invalid email format', () => {
      expect(() =>
        validateUpdateUserInput({ email: 'notanemail' }),
      ).toThrow('Invalid email format');
    });

    it('should pass for valid email update', () => {
      expect(() =>
        validateUpdateUserInput({ email: 'new@example.com' }),
      ).not.toThrow();
    });
  });
});

import { describe, it, expect } from 'vitest';
import { shouldSendNotification } from '../../src/validators/notification.validator.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    recipient: 'user@example.com',
    subject: 'Test',
    body: 'Test body',
    channel: 'email',
    type: 'order_confirmation',
    priority: 'normal',
    ...overrides,
  };
}

function makePrefs(overrides: Partial<UserPreferences['email']> = {}): UserPreferences {
  return {
    id: 'pref-1',
    userId: 'user-1',
    email: {
      enabled: true,
      frequency: 'realtime',
      subscribedTypes: [
        'order_confirmation',
        'order_status_update',
        'user_welcome',
        'user_update',
        'system_alert',
      ],
      ...overrides,
    },
    createdAt: new Date(),
    updatedAt: new Date(),
  };
}

describe('Notification Validators', () => {
  describe('shouldSendNotification', () => {
    it('should allow notification when no preferences exist (opt-out model)', () => {
      expect(shouldSendNotification(undefined, makePayload())).toBe(true);
    });

    it('should allow notification when preferences allow it', () => {
      expect(shouldSendNotification(makePrefs(), makePayload())).toBe(true);
    });

    it('should block notification when email is disabled', () => {
      const prefs = makePrefs({ enabled: false });
      expect(shouldSendNotification(prefs, makePayload())).toBe(false);
    });

    it('should block notification when type is not subscribed', () => {
      const prefs = makePrefs({ subscribedTypes: ['system_alert'] });
      expect(
        shouldSendNotification(prefs, makePayload({ type: 'order_confirmation' })),
      ).toBe(false);
    });

    it('should allow urgent notifications even when email is disabled', () => {
      const prefs = makePrefs({ enabled: false });
      expect(
        shouldSendNotification(prefs, makePayload({ priority: 'urgent' })),
      ).toBe(true);
    });

    it('should allow urgent notifications even when type is not subscribed', () => {
      const prefs = makePrefs({ subscribedTypes: [] });
      expect(
        shouldSendNotification(prefs, makePayload({ priority: 'urgent' })),
      ).toBe(true);
    });

    it('should allow non-email channel notifications regardless of email preferences', () => {
      const prefs = makePrefs({ enabled: false });
      expect(
        shouldSendNotification(prefs, makePayload({ channel: 'sms' })),
      ).toBe(true);
    });

    it('should allow notification for subscribed type', () => {
      const prefs = makePrefs({ subscribedTypes: ['order_confirmation'] });
      expect(
        shouldSendNotification(prefs, makePayload({ type: 'order_confirmation' })),
      ).toBe(true);
    });
  });
});
